/// <summary>
/// extension of table <c>InventTrans</c>
/// </summary>
[ExtensionOf(tablestr(InventTrans))]
internal final class ETGInventTrans_Extension
{

}

Method.Source:
public static DimensionDefault getDefaultDimensionETG(InventTransOrigin inventTransOrigin)
{
    DimensionDefault  dimDefault;
    InventJournalTrans inventJournalTrans;

    if(!inventTransOrigin)
    {
        return 0;
    }
    switch(inventTransOrigin.ReferenceCategory)
    {
        case InventTransType::Purch:
            dimDefault = PurchLine::findInventTransId(inventTransOrigin.InventTransId).DefaultDimension;
            break;
        case InventTransType::Sales:
            dimDefault = SalesLine::findInventTransId(inventTransOrigin.InventTransId).DefaultDimension;
            break;
        case InventTransType::InventTransfer:
            inventJournalTrans=InventJournalTrans::findInventTransId(inventTransOrigin.InventTransId);
            //dimDefault = InventJournalTrans::findInventTransId(inventTransOrigin.InventTransId).DefaultDimension;
            dimDefault=inventJournalTrans.DefaultDimension;

            if(!dimDefault)
            {
                select * from inventJournalTrans where inventJournalTrans.ToInventTransId == inventTransOrigin.InventTransId;

                dimDefault = inventJournalTrans.DefaultDimension;
            }

            InventJournalTable inventJournalTable = inventJournalTrans.inventJournalTable();
            if(InventTrans::findByInventTransOrigin(inventTransOrigin.RecId).StatusReceipt == StatusReceipt::Purchased &&
             inventJournalTable.inventJournalName().ETGTransferJournalFDChange == NoYes::Yes)
            {
                dimDefault = inventJournalTrans.ETGToDefaultDimension;
            }
            break;
        case InventTransType::TransferOrderShip:
            dimDefault = InventTransferLine::findTransIdShip(inventTransOrigin.InventTransId).ETGDefaultDimension;
            break;
        case InventTransType::TransferOrderReceive:
            dimDefault = InventTransferLine::findTransIdReceive(inventTransOrigin.InventTransId).ETGDefaultDimension;
            break;
        case InventTransType::TransferOrderScrap:
            dimDefault = InventTransferLine::findTransIdScrap(inventTransOrigin.InventTransId).ETGDefaultDimension;
            break;
        case InventTransType::InventTransaction:
            dimDefault = InventJournalTrans::findInventTransId(inventTransOrigin.InventTransId).DefaultDimension;
            break;
        case InventTransType::InventLossProfit:
            dimDefault = InventJournalTrans::findInventTransId(inventTransOrigin.InventTransId).DefaultDimension;
            break;
        case InventTransType::InventCounting:
            dimDefault = InventJournalTrans::findInventTransId(inventTransOrigin.InventTransId).DefaultDimension;
            break;

        //for BOM & production
        case InventTransType::BOMMain:
            dimDefault = InventJournalTrans::findInventTransId(InventTransOrigin.InventTransId).DefaultDimension;
            break;
        case InventTransType::BOMLine:
            dimDefault = InventJournalTrans::findInventTransId(InventTransOrigin.InventTransId).DefaultDimension;
            break;
        case InventTransType::Production:
            dimDefault = ProdTable::find(InventTransOrigin.ReferenceId).DefaultDimension;
            break;
        case InventTransType::ProdLine:
            dimDefault = ProdTable::find(InventTransOrigin.ReferenceId).DefaultDimension;
            break;
        case InventTransType::PmfProdCoBy:
            dimDefault = ProdTable::find(InventTransOrigin.ReferenceId).DefaultDimension;
            break;
        case InventTransType::ProdRelease_RU:
            dimDefault = ProdTable::find(InventTransOrigin.ReferenceId).DefaultDimension;
            break;

    }

    return dimDefault;
}

/// <summary>
/// get unit price inventory transaction
/// </summary>
/// <param name = "_inventTrans">InventTrans _inventTrans</param>
/// <returns>CostPrice</returns>
[SysClientCacheDataMethodAttribute(true)]
public static display CostPrice getUnitPriceETG(InventTrans _inventTrans)
{
    if(_inventTrans.Qty == 0)
    {
        return 0;
    }
    else
    {
        return _inventTrans.costValue() / _inventTrans.Qty;
    }
}

/// <summary>
/// get sales price of sales line 
/// </summary>
/// <param name = "_inventTrans">InventTrans _inventTrans</param>
/// <returns>SalesPrice</returns>
[SysClientCacheDataMethodAttribute(true)]
public static display SalesPrice getSalesPriceETG(InventTrans _inventTrans)
{
    InventTransOrigin inventTransOriginETG = _inventTrans.inventTransOrigin();
    if(inventTransOriginETG.ReferenceCategory == InventTransType::Sales)
    {
        return SalesLine::findInventTransId(inventTransOriginETG.InventTransId).SalesPrice;
    }
    else
    {
        return 0;
    }
}

/// <summary>
/// get vertical from financial dimesnions of transactions
/// </summary>
/// <param name = "_inventTrans">InventTrans _inventTrans</param>
/// <returns>ETGVertical</returns>
[SysClientCacheDataMethodAttribute(true)]
public static display ETGVertical getVerticalETG(InventTrans _inventTrans)
{
    if(ETGACFParameters::find().EnableVerticalSubVerticalFields == NoYes::No)
    {
        return "";
    }

    try
    {
        InventTransOrigin inventTransOrigin = _inventTrans.inventTransOrigin();
        if(!inventTransOrigin)
        {
            return "";
        }

        DimensionDefault  dimDefault = InventTrans::getDefaultDimensionETG(inventTransOrigin);

        if(dimDefault)
        {
            return ETGFixedAssetFinancialsDimensions::getDimensionDisplayValueCodeOnlyETG(dimDefault, ETGACFParameters::find().Vertical);
        }
        else
        {
            return "";
        }
    }
    catch(Exception::Error)
    {
        return "";
    }
    catch
    {
        return "";
    }

}

