/// <summary>
/// Invoice Number field added on Inventotory management transaction form.
/// </summary>
/// <returns></returns>
public display InvoiceId displayInvoiceId()
{
    InvoiceId invoiceId = '';

    InventTransOrigin inventTransOrigin;
    VendInvoiceTrans vendInvoiceTrans;
    CustInvoiceTrans custInvoiceTrans;

    select firstonly inventTransOrigin
        where inventTransOrigin.RecId == this.InventTransOrigin;

    if (this.StatusReceipt == StatusReceipt::Purchased)
    {
        select firstonly InvoiceId
            from vendInvoiceTrans
            where vendInvoiceTrans.InventTransId == inventTransOrigin.InventTransId;

        invoiceId = vendInvoiceTrans.InvoiceId;
    }
    else if (this.StatusIssue == StatusIssue::Sold)
    {
        select firstonly InvoiceId
            from custInvoiceTrans
            where custInvoiceTrans.InventTransId == inventTransOrigin.InventTransId;

        invoiceId = custInvoiceTrans.InvoiceId;
    }

    return invoiceId;
}
